import{_ as a,H as n,f as s,i as o}from"./chunks/framework.BHvCMIhP.js";const h=JSON.parse('{"title":"JIT 心智","description":"","frontmatter":{},"headers":[],"relativePath":"interpreterLearning/28-JIT心智.md","filePath":"interpreterLearning/28-JIT心智.md","lastUpdated":1778496697000}'),e={name:"interpreterLearning/28-JIT心智.md"};function r(i,t,p,d,c,l){return n(),s("div",null,[...t[0]||(t[0]=[o(`<h1 id="jit-心智" tabindex="-1">JIT 心智 <a class="header-anchor" href="#jit-心智" aria-label="Permalink to &quot;JIT 心智&quot;">​</a></h1><p>到 27 篇为止,Mochi 已经是个能跑的字节码 VM——但它再怎么优化也只能到 CPython 3.11 的 1/10。<strong>剩下那 10 倍差距,全在 JIT 上</strong>。V8 比 Python 快 10-100 倍、HotSpot 比 CPython 快 50 倍,<strong>核心就一件事</strong>:把&quot;热点&quot;字节码翻译成 native 机器码,跳过 dispatch 循环。这一篇不写 SSA、不写寄存器分配——<strong>只搭一个&quot;看 V8 / LuaJIT 源码不慌&quot;的心智图</strong>,讲清楚 JIT 三大流派、type specialization / inline cache / deoptimization 三个关键词、V8 多 tier 怎么协作。Mochi 不实现 JIT——<strong>30-50k 行代码的事,玩具语言不上</strong>——但这一篇之后,你再看 V8 那堆 tier 的命名,脑子里有图。</p><blockquote><p>一句话先记住:<strong>JIT = Just-In-Time,运行时把热点字节码翻译成 native 机器码,跳过 dispatch</strong>。三大流派<strong>模板 / 方法 / Tracing</strong>——模板最简单(LuaJIT stage1 / V8 Sparkplug),方法最主流(V8 TurboFan / HotSpot C2),Tracing 跨方法优化最激进(LuaJIT / PyPy)。<strong>没有 type specialization + inline cache + deoptimization 这三件套,JIT 是空话</strong>——它们决定了优化代码什么时候快、什么时候要倒退回解释器。</p></blockquote><hr><h2 id="一、为什么-jit-比解释器快-10-100-倍" tabindex="-1">一、为什么 JIT 比解释器快 10-100 倍 <a class="header-anchor" href="#一、为什么-jit-比解释器快-10-100-倍" aria-label="Permalink to &quot;一、为什么 JIT 比解释器快 10-100 倍&quot;">​</a></h2><p>字节码解释器每条指令大致这样跑:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>取下一条字节码 (1 cycle)</span></span>
<span class="line"><span>查 dispatch 表跳转 (1-3 cycles, 分支预测失败更慘)</span></span>
<span class="line"><span>取操作数 → 执行 (1-2 cycle)</span></span>
<span class="line"><span>更新 PC → goto next</span></span></code></pre></div><p><strong>纯执行只有 1 cycle</strong>,<strong>dispatch 开销占 70%</strong>。JIT 的核心思想:<strong>把这堆字节码直接拼成机器码</strong>,dispatch 没了、PC 自增没了、操作数取址 inline 了。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>字节码:                       JIT 生成的 x86-64:</span></span>
<span class="line"><span>  LOAD_FAST  a                   mov rax, [rbp-8]      ; a</span></span>
<span class="line"><span>  LOAD_FAST  b                   add rax, [rbp-16]     ; + b</span></span>
<span class="line"><span>  BINARY_ADD                     mov [rbp-24], rax     ; c</span></span>
<span class="line"><span>  STORE_FAST c</span></span></code></pre></div><p><strong>3 条机器指令,直接跑完</strong>——之前要走 4 条字节码、每条 dispatch 5-10 cycle。这就是 10x。</p><hr><h2 id="二、jit-三大流派" tabindex="-1">二、JIT 三大流派 <a class="header-anchor" href="#二、jit-三大流派" aria-label="Permalink to &quot;二、JIT 三大流派&quot;">​</a></h2><h3 id="_2-1-模板-jit-template-baseline" tabindex="-1">2.1 模板 JIT(template / baseline) <a class="header-anchor" href="#_2-1-模板-jit-template-baseline" aria-label="Permalink to &quot;2.1 模板 JIT(template / baseline)&quot;">​</a></h3><p><strong>每条字节码对应一段预先写好的机器码模板,拼起来</strong>——实现简单,编译速度极快,优化空间小。代表:V8 早期 Full-codegen、<strong>LuaJIT 第一阶段</strong>、<strong>V8 Sparkplug</strong>(2021 加的 baseline tier)。</p><p><strong>Sparkplug 的存在感</strong>:V8 团队发现&quot;从 Ignition 直接上 TurboFan 太慢&quot;,中间加了 Sparkplug——<strong>编译比 TurboFan 快 100 倍,运行比 Ignition 快 ~50%</strong>。<strong>模板 JIT 不死,反而在大厂复活了</strong>。</p><h3 id="_2-2-方法-jit-method-based" tabindex="-1">2.2 方法 JIT(method-based) <a class="header-anchor" href="#_2-2-方法-jit-method-based" aria-label="Permalink to &quot;2.2 方法 JIT(method-based)&quot;">​</a></h3><p>拿<strong>整个方法</strong>当编译单元——构建 IR(通常 SSA)→ 跑一堆优化 pass → 输出机器码。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>function add(a, b) { return a + b }</span></span>
<span class="line"><span>  ↓ 构建 SSA</span></span>
<span class="line"><span>  ↓ Pass: inlining / constant prop / dead code elim</span></span>
<span class="line"><span>  ↓ Pass: register allocation</span></span>
<span class="line"><span>  ↓ 输出: 几十条 x86 指令</span></span></code></pre></div><p>优化深、性能巅峰最高;编译慢、内存吃。代表:<strong>HotSpot C1 / C2</strong>、<strong>V8 TurboFan</strong>、<strong>V8 Maglev</strong>(2023+ 中端 tier)。<strong>C2 / TurboFan 是这个流派的工业标杆</strong>——产出的代码常常比 C 还快(因为有运行时类型信息可以 specialize)。</p><h3 id="_2-3-tracing-jit" tabindex="-1">2.3 Tracing JIT <a class="header-anchor" href="#_2-3-tracing-jit" aria-label="Permalink to &quot;2.3 Tracing JIT&quot;">​</a></h3><p><strong>不按方法切,按实际跑过的&quot;热路径&quot;切</strong>——记录一段真实运行轨迹(trace),把这条路径上跨越的所有方法都 inline 成一坨。<strong>跨方法内联粒度极激进</strong>,<strong>热路径性能炸裂</strong>;trace 是动态的——分支爆炸时代码会爆。代表:<strong>LuaJIT</strong>(教科书级实现)、<strong>PyPy</strong>、SpiderMonkey 早期 TraceMonkey。</p><p>LuaJIT 是这个流派的标杆——<strong>Mike Pall 一个人写的</strong>,在动态语言里跑出过接近 C 的性能。<strong>想看真东西就读它,40k 行 C 看得完</strong>。</p><h3 id="_2-4-三派对比" tabindex="-1">2.4 三派对比 <a class="header-anchor" href="#_2-4-三派对比" aria-label="Permalink to &quot;2.4 三派对比&quot;">​</a></h3><table tabindex="0"><thead><tr><th>维度</th><th>模板 JIT</th><th>方法 JIT</th><th>Tracing JIT</th></tr></thead><tbody><tr><td>编译单元</td><td>单条字节码</td><td>整个方法</td><td>实际 trace</td></tr><tr><td>实现代码量</td><td>5k 行</td><td>30-50k 行</td><td>20-40k 行</td></tr><tr><td>编译速度</td><td>极快(ms)</td><td>慢(几十 ms)</td><td>中等</td></tr><tr><td>峰值性能</td><td>1.5-3x 解释器</td><td>10-100x</td><td>10-100x</td></tr><tr><td>代表</td><td>V8 Sparkplug</td><td>HotSpot C2 / TurboFan</td><td>LuaJIT / PyPy</td></tr></tbody></table><hr><h2 id="三、jit-三件套-type-specialization-inline-cache-deopt" tabindex="-1">三、JIT 三件套:type specialization / inline cache / deopt <a class="header-anchor" href="#三、jit-三件套-type-specialization-inline-cache-deopt" aria-label="Permalink to &quot;三、JIT 三件套:type specialization / inline cache / deopt&quot;">​</a></h2><h3 id="_3-1-type-specialization" tabindex="-1">3.1 Type specialization <a class="header-anchor" href="#_3-1-type-specialization" aria-label="Permalink to &quot;3.1 Type specialization&quot;">​</a></h3><p>动态语言里,<code>a + b</code> 的解释器版本要查类型、走分支——<strong>慢就慢在每次都要查</strong>。但运行时观察,<strong>99% 的实际调用都是 int + int</strong>。JIT 的做法:<strong>编一个只处理 int + int 的特化版本</strong>,前面加一个<strong>类型守卫(type guard)</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>  cmp [a_tag], INT</span></span>
<span class="line"><span>  jne deopt           ← 不是 int 就退回解释器</span></span>
<span class="line"><span>  cmp [b_tag], INT</span></span>
<span class="line"><span>  jne deopt</span></span>
<span class="line"><span>  mov rax, [a_val]; add rax, [b_val]; ret</span></span></code></pre></div><p>99% 命中,1% deopt——<strong>平均下来比通用版本快 10x</strong>。</p><h3 id="_3-2-inline-cache-ic" tabindex="-1">3.2 Inline cache(IC) <a class="header-anchor" href="#_3-2-inline-cache-ic" aria-label="Permalink to &quot;3.2 Inline cache(IC)&quot;">​</a></h3><p>JS 里 <code>obj.x</code> 是个 hash 查找——慢得离谱。<strong>V8 的发明</strong>:第一次访问 <code>obj.x</code> 时,记下 obj 的 shape(hidden class)+ x 的 offset,后面再访问同 shape 的对象,<strong>直接读那个 offset</strong>——<code>src/ic/</code> 整个目录都在做这个。Chromium 团队 2010 年左右真的靠&quot;把 IC 写好&quot;打赢了 Firefox。</p><p><strong>多态 IC</strong>:同一个 call site 见过多个 shape——退化成短链(monomorphic → polymorphic → megamorphic)。<strong>3 个 shape 之内基本无损,4 个以上性能开始崩</strong>。这就是 React fiber 内部 schema 严格统一的工程原因之一。</p><h3 id="_3-3-deoptimization" tabindex="-1">3.3 Deoptimization <a class="header-anchor" href="#_3-3-deoptimization" aria-label="Permalink to &quot;3.3 Deoptimization&quot;">​</a></h3><p>JIT 是<strong>乐观优化</strong>——假设&quot;以后跟现在一样&quot;。<strong>这个假设错了</strong>(对象 shape 变了 / 类型变了)就必须<strong>扔掉优化代码,退回 Ignition 字节码解释器</strong>。一次 deopt 几百 us 到几 ms——<strong>频繁 deopt 的代码性能比纯解释器还差</strong>——这就是写&quot;V8 友好的 JS&quot;的核心:<strong>别让 V8 反复猜错</strong>(类型稳定、shape 稳定、参数 arity 稳定)。</p><hr><h2 id="四、v8-现实-多-tier-协作" tabindex="-1">四、V8 现实:多 tier 协作 <a class="header-anchor" href="#四、v8-现实-多-tier-协作" aria-label="Permalink to &quot;四、V8 现实:多 tier 协作&quot;">​</a></h2><p>2026 年的 V8 实际上有<strong>四个 tier</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌──────────┐  ~50 次  ┌──────────┐  ~1000 次 ┌──────────┐  ~10000 次 ┌──────────┐</span></span>
<span class="line"><span>│ Ignition │ ────────→│ Sparkplug│ ─────────→│  Maglev  │ ──────────→│ TurboFan │</span></span>
<span class="line"><span>│ (解释)   │           │ (模板JIT)│           │ (中端JIT)│            │ (顶级JIT)│</span></span>
<span class="line"><span>└──────────┘           └──────────┘           └──────────┘            └──────────┘</span></span>
<span class="line"><span>     ↑                                                                       │</span></span>
<span class="line"><span>     └─────────────────── 任一 tier 类型猜错 → deopt ─────────────────────────┘</span></span></code></pre></div><p><strong>为什么要四个 tier</strong>:每层是<strong>编译速度 vs 运行速度</strong>的权衡——刚跑两次用解释器最划算,跑 50 次 Sparkplug 几乎免费拿 50% 加速,真正的热代码再上 TurboFan。<strong>Sparkplug(2021)、Maglev(2023)都是这几年新加的</strong>——说明哪怕 V8 这么强,中间地带的优化空间还很大。</p><hr><h2 id="五、mochi-这里偷懒了" tabindex="-1">五、Mochi 这里偷懒了 <a class="header-anchor" href="#五、mochi-这里偷懒了" aria-label="Permalink to &quot;五、Mochi 这里偷懒了&quot;">​</a></h2><p><strong>Mochi 不实现 JIT</strong>——本系列只到字节码 VM + GC。真要做 JIT,<strong>保守估计 30-50k 行代码</strong>——而且工程难点不在&quot;翻译字节码到机器码&quot;,<strong>难点是 deopt、是 IC、是多 tier 协作、是回归测试</strong>。</p><p>如果你看完还是想做,<strong>最划算的路线是上 LLVM</strong>——把 Mochi 字节码翻成 LLVM IR,让 LLVM 干所有的优化和寄存器分配。<strong>Crystal 语言、Numba(Python JIT)走的都是这条路</strong>。<strong>LLVM 后端 ~3k 行代码搞定一个能跑的 JIT</strong>——比从零写省 10 倍。</p><hr><h2 id="六、工业指针-看-jit-源码该去哪" tabindex="-1">六、工业指针:看 JIT 源码该去哪 <a class="header-anchor" href="#六、工业指针-看-jit-源码该去哪" aria-label="Permalink to &quot;六、工业指针:看 JIT 源码该去哪&quot;">​</a></h2><table tabindex="0"><thead><tr><th>项目</th><th>JIT 路径</th><th>推荐入口</th></tr></thead><tbody><tr><td>V8</td><td><code>src/compiler/</code> <code>src/maglev/</code> <code>src/baseline/</code></td><td><code>src/compiler/pipeline.cc</code>(TurboFan 主流程)</td></tr><tr><td>HotSpot</td><td><code>src/hotspot/share/c1/</code> <code>src/hotspot/share/opto/</code>(C2)</td><td><code>opto/compile.cpp</code>(C2 主流程)</td></tr><tr><td>LuaJIT</td><td><code>src/lj_record.c</code> <code>src/lj_asm.c</code></td><td><code>lj_record.c</code>(tracing 起点)</td></tr><tr><td>PyPy</td><td><code>rpython/jit/metainterp/</code></td><td><code>metainterp.py</code></td></tr><tr><td>.NET RyuJIT</td><td><code>src/coreclr/jit/</code></td><td><code>compiler.cpp</code></td></tr></tbody></table><p><strong>看顺序建议</strong>:<strong>LuaJIT 先看</strong>——单人作品、紧凑、Tracing JIT 教科书。<strong>V8 第二</strong>——多 tier 设计最现代。<strong>HotSpot 最后</strong>——历史包袱重但 C2 优化质量至今无对手。</p><hr><h2 id="七、踩坑提醒" tabindex="-1">七、踩坑提醒 <a class="header-anchor" href="#七、踩坑提醒" aria-label="Permalink to &quot;七、踩坑提醒&quot;">​</a></h2><ol><li><strong>以为 JIT = 编译器</strong>——多出来的难点全在 deopt 和 IC</li><li><strong>以为 type specialization 就是&quot;加类型注解&quot;</strong>——不,是<strong>运行时观察 + 加 guard</strong></li><li><strong>以为 V8 / HotSpot 越跑越快</strong>——deopt 触发后<strong>比解释器还慢</strong>,要 warm up</li><li><strong>同一函数传四种以上 shape 的对象</strong>——megamorphic IC,性能崩</li><li><strong>频繁 try/catch + throw</strong>——常常打破 JIT 假设</li><li><strong>delete obj.x</strong>——直接破坏 hidden class,触发 deopt</li><li><strong>arguments.callee / with / eval</strong>——上古 JS 语法,V8 直接放弃 JIT</li><li><strong>以为 Tracing JIT 包打天下</strong>——分支多 trace 会爆,SpiderMonkey 后来抛弃了 TraceMonkey</li><li><strong>以为可以&quot;手写汇编 JIT&quot;</strong>——能,但 deopt / GC 集成几乎让你自杀</li><li><strong>不区分启动期 / 稳态性能</strong>——Java 服务前 30 秒慢是正常,等 C2 编完就起飞</li></ol><hr><p>下一篇:<code>29-真实语言剖析.md</code>,<strong>全系列密度最高的对照篇</strong>——把 CPython / V8 / Lua / JVM 一个一个拆开,<strong>每家&quot;对应到 Mochi 里的哪一部分&quot;</strong>,带具体文件名、类名、入口函数。读完 Mochi 看这一篇,然后去啃真实语言源码——这是 27 篇 Mochi 之后,<strong>真正&quot;接入工业级语言&quot;的那一步</strong>。</p>`,53)])])}const u=a(e,[["render",r]]);export{h as __pageData,u as default};
